# Module providing shape base classes and interfaces

interface Drawable:
    def draw(self) -> str: ...

@abstract
class Shape:
    _name: str

    def __init__(self, name: str):
        self._name = name

    property get name(self) -> str:
        return self._name

    @abstract
    def area(self) -> float: ...

    @virtual
    def describe(self) -> str:
        return f"Shape: {self._name}"

class Rectangle(Shape):
    _width: float
    _height: float

    def __init__(self, name: str, width: float, height: float):
        super().__init__(name)
        self._width = width
        self._height = height

    @override
    def area(self) -> float:
        return self._width * self._height

    @override
    def describe(self) -> str:
        return f"Rectangle {self._name}: {self._width} x {self._height}"

class Circle(Shape):
    _radius: float

    def __init__(self, name: str, radius: float):
        super().__init__(name)
        self._radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self._radius * self._radius

    @override
    def describe(self) -> str:
        return f"Circle {self._name}: radius={self._radius}"
